{"file_text": "@using sv_6d4ad0f438be40cca3bb8b6f0388a2d1.Services
@inject IJSRuntime JS

<section class="message-area @(ThreadOpen ? "thread-open" : "")">
    @if (Channel is not null)
    {
        <div class="message-header">
            <h2># @Channel.Name</h2>
            <span class="channel-desc">@Channel.Description</span>
        </div>

        <div class="message-list" @ref="messageListRef" @onscroll="HandleScroll">
            @if (IsLoadingMore)
            {
                <div class="loading-indicator">Loading older messages…</div>
            }

            @foreach (var msg in Messages.Where(m => m.ReplyToId is null))
            {
                <MessageItem Message="msg"
                             ReplyCount="GetReplyCount(msg.Id)"
                             OnOpenThread="OnOpenThread"
                             OnReact="OnReact" />
            }
        </div>

        <div class="message-input">
            <textarea @bind="newMessage"
                      @bind:event="oninput"
                      @onkeydown="HandleKeyDown"
                      placeholder="Message #@Channel.Name"
                      rows="2"></textarea>
            <button class="btn-send" @onclick="SendAsync" disabled="@string.IsNullOrWhiteSpace(newMessage)">
                Send
            </button>
        </div>
    }
    else
    {
        <div class="no-channel">
            <p>Select a channel to start chatting</p>
        </div>
    }
</section>

@code {
    [Parameter, EditorRequired] public List<Message> Messages { get; set; } = new();
    [Parameter] public Channel? Channel { get; set; }
    [Parameter] public Dictionary<int, int> ThreadReplyCounts { get; set; } = new();
    [Parameter] public bool IsLoadingMore { get; set; }
    [Parameter] public bool ThreadOpen { get; set; }
    [Parameter] public EventCallback<string> OnSendMessage { get; set; }
    [Parameter] public EventCallback<int> OnOpenThread { get; set; }
    [Parameter] public EventCallback<(int, string)> OnReact { get; set; }
    [Parameter] public EventCallback OnLoadMore { get; set; }

    private string newMessage = "";
    private ElementReference messageListRef;
    private int? previousChannelId;
    private int previousMessageCount;

    private int GetReplyCount(int messageId) =>
        ThreadReplyCounts.TryGetValue(messageId, out var count) ? count : 0;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        // Scroll to bottom when channel changes or new messages arrive
        var currentCount = Messages.Count;
        if (Channel is not null &&
            (Channel.Id != previousChannelId || currentCount > previousMessageCount))
        {
            previousChannelId = Channel.Id;
            previousMessageCount = currentCount;

            try
            {
                await JS.InvokeVoidAsync("eval",
                    "document.querySelector('.message-list')?.scrollTo(0, document.querySelector('.message-list')?.scrollHeight)");
            }
            catch (JSDisconnectedException) { }
        }
    }

    private async Task HandleScroll()
    {
        // Load more when scrolled near the top
        try
        {
            var scrollTop = await JS.InvokeAsync<double>("eval",
                "document.querySelector('.message-list')?.scrollTop ?? 0");

            if (scrollTop < 50)
            {
                await OnLoadMore.InvokeAsync();
            }
        }
        catch (JSDisconnectedException) { }
    }

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e is { Key: "Enter", ShiftKey: false })
        {
            await SendAsync();
        }
    }

    private async Task SendAsync()
    {
        if (string.IsNullOrWhiteSpace(newMessage)) return;

        var content = newMessage.Trim();
        newMessage = "";
        await OnSendMessage.InvokeAsync(content);
    }
}
