    private List<Channel> channels = new();
    private int? selectedChannelId;
    private List<Message> messages = new();
    private Dictionary<int, int> threadReplyCounts = new();
    private int messagesSkip;
    private bool isLoadingMore;
    private const int PageSize = 50;

    private int? activeThreadRootId;
    private Message? threadRootMessage;
    private List<Message> threadReplies = new();

    private Channel? SelectedChannel =>
        channels.FirstOrDefault(c => c.Id == selectedChannelId);

