    private async Task SelectChannelAsync(int channelId)
    {
        if (selectedChannelId == channelId) return;

        selectedChannelId = channelId;
        messagesSkip = 0;
        activeThreadRootId = null;

        messages = await ChatService.GetMessagesAsync(channelId, 0, PageSize);
        messagesSkip = messages.Count;

        ComputeThreadReplyCounts();

        await ChatService.MarkChannelReadAsync(channelId);

        // Refresh channel list to clear unread badge
        channels = await ChatService.GetChannelsAsync();
    }

    private async Task LoadMoreMessagesAsync()
    {
        if (isLoadingMore || selectedChannelId is null) return;

        isLoadingMore = true;
        StateHasChanged();

        var older = await ChatService.GetMessagesAsync(selectedChannelId.Value, messagesSkip, PageSize);

        if (older.Count > 0)
        {
            messages.InsertRange(0, older);
            messagesSkip += older.Count;
            ComputeThreadReplyCounts();
        }

        isLoadingMore = false;
    }

    private void ComputeThreadReplyCounts()
    {
        threadReplyCounts = messages
            .Where(m => m.ReplyToId.HasValue)
            .GroupBy(m => m.ReplyToId!.Value)
            .ToDictionary(g => g.Key, g => g.Count());
    }

    private async Task SendMessageAsync(string content)
    {
        if (selectedChannelId is null || string.IsNullOrWhiteSpace(content)) return;

        var msg = await ChatService.SendMessageAsync(selectedChannelId.Value, content, null);
        messages.Add(msg);
    }

    private async Task OpenThreadAsync(int rootMessageId)
    {
        activeThreadRootId = rootMessageId;
        threadRootMessage = messages.FirstOrDefault(m => m.Id == rootMessageId);

        var allThreadMessages = await ChatService.GetThreadAsync(rootMessageId);
        threadReplies = allThreadMessages.Where(m => m.Id != rootMessageId).ToList();
    }

    private async Task SendThreadReplyAsync(string content)
    {
        if (activeThreadRootId is null || selectedChannelId is null
            || string.IsNullOrWhiteSpace(content)) return;

        var reply = await ChatService.SendMessageAsync(
            selectedChannelId.Value, content, activeThreadRootId.Value);
        threadReplies.Add(reply);
        messages.Add(reply);
        ComputeThreadReplyCounts();
    }

    private async Task ReactAsync((int MessageId, string Emoji) args)
    {
        await ChatService.AddReactionAsync(args.MessageId, args.Emoji);

        // Refresh messages to show updated reactions
        if (selectedChannelId is not null)
        {
            messages = await ChatService.GetMessagesAsync(
                selectedChannelId.Value, 0, messagesSkip > 0 ? messagesSkip : PageSize);
        }
    }

    private void CloseThread()
    {
        activeThreadRootId = null;
        threadRootMessage = null;
        threadReplies.Clear();
    }
}

