@using sv_6d4ad0f438be40cca3bb8b6f0388a2d1.Services

<aside class="thread-panel">
    <div class="thread-header">
        <h3>Thread</h3>
        <button class="close-btn" @onclick="OnClose" title="Close thread">✕</button>
    </div>

    @if (RootMessage is not null)
    {
        <div class="thread-root-quote">
            <span class="author">@RootMessage.Author</span>
            <p>@RootMessage.Content</p>
        </div>
    }

    <div class="thread-replies">
        @if (Replies.Count == 0)
        {
            <p class="no-replies">No replies yet</p>
        }

        @foreach (var reply in Replies)
        {
            <div class="thread-reply">
                <div class="message-meta">
                    <span class="author">@reply.Author</span>
                    <span class="timestamp">@FormatRelativeTime(reply.SentAt)</span>
                </div>
                <div class="message-content">@reply.Content</div>
            </div>
        }
    </div>

    <div class="thread-input">
        <textarea @bind="replyText"
                  @bind:event="oninput"
                  @onkeydown="HandleKeyDown"
                  placeholder="Reply…"
                  rows="2"></textarea>
        <button class="btn-send" @onclick="SendReplyAsync"
                disabled="@string.IsNullOrWhiteSpace(replyText)">
            Reply
        </button>
    </div>
</aside>

@code {
    [Parameter] public Message? RootMessage { get; set; }
    [Parameter, EditorRequired] public List<Message> Replies { get; set; } = new();
    [Parameter] public EventCallback<string> OnReply { get; set; }
    [Parameter] public EventCallback OnClose { get; set; }

    private string replyText = "";

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e is { Key: "Enter", ShiftKey: false })
        {
            await SendReplyAsync();
        }
    }

    private async Task SendReplyAsync()
    {
        if (string.IsNullOrWhiteSpace(replyText)) return;

        var content = replyText.Trim();
        replyText = "";
        await OnReply.InvokeAsync(content);
    }

    private static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.UtcNow - sentAt.ToUniversalTime();

        return diff.TotalSeconds switch
        {
            < 60 => "just now",
            < 3600 => $"{(int)diff.TotalMinutes} min ago",
            < 86400 => $"{(int)diff.TotalHours}h ago",
            < 604800 => $"{(int)diff.TotalDays}d ago",
            _ => sentAt.ToString("MMM d, yyyy")
        };
    }
}

