arguments.file_text:
/* ===== Chat Layout ===== */

::deep .chat-container {
    display: flex;
    height: 100vh;
    font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif;
    background: #1a1d21;
    color: #d1d2d3;
}

/* ===== Channel Sidebar ===== */

::deep .channel-sidebar {
    width: 20%;
    min-width: 200px;
    background: #19171d;
    border-right: 1px solid #2c2d30;
    display: flex;
    flex-direction: column;
    overflow: hidden;
}

::deep .sidebar-header {
    padding: 16px 16px 8px;
    border-bottom: 1px solid #2c2d30;
}

::deep .sidebar-header h3 {
    margin: 0;
    font-size: 1.1rem;
    color: #fff;
}

::deep .channel-list {
    list-style: none;
    padding: 8px 0;
    margin: 0;
    overflow-y: auto;
    flex: 1;
}

::deep .channel-item {
    padding: 6px 16px;
    cursor: pointer;
    border-left: 3px solid transparent;
    transition: background 0.15s;
    position: relative;
}

::deep .channel-item:hover {
    background: #27242c;
}

::deep .channel-item.active {
    background: #1164a3;
    border-left-color: #fff;
}

::deep .channel-name {
    font-weight: 600;
    font-size: 0.95rem;
    color: #fff;
}

::deep .channel-description {
    font-size: 0.75rem;
    color: #9e9ea6;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
    margin-top: 2px;
}

::deep .unread-badge {
    position: absolute;
    right: 12px;
    top: 50%;
    transform: translateY(-50%);
    background: #e01e5a;
    color: #fff;
    font-size: 0.7rem;
    font-weight: 700;
    padding: 1px 6px;
    border-radius: 10px;
    min-width: 18px;
    text-align: center;
}

/* ===== Message Area ===== */

::deep .message-area {
    flex: 1;
    display: flex;
    flex-direction: column;
    min-width: 0;
    background: #1a1d21;
}

::deep .message-area.thread-open {
    /* shrinks when thread panel is open */
}

::deep .message-header {
    padding: 12px 20px;
    border-bottom: 1px solid #2c2d30;
    flex-shrink: 0;
}

::deep .message-header h2 {
    margin: 0;
    font-size: 1.1rem;
    color: #fff;
}

::deep .channel-desc {
    font-size: 0.8rem;
    color: #9e9ea6;
}

::deep .message-list {
    flex: 1;
    overflow-y: auto;
    padding: 12px 20px;
}

::deep .loading-indicator {
    text-align: center;
    padding: 12px;
    color: #9e9ea6;
    font-size: 0.85rem;
}

::deep .no-channel {
    display: flex;
    align-items: center;
    justify-content: center;
    flex: 1;
    color: #9e9ea6;
    font-size: 1.1rem;
}

/* ===== Message Item ===== */

::deep .message-item {
    padding: 8px 12px;
    border-radius: 6px;
    position: relative;
    margin-bottom: 2px;
    transition: background 0.1s;
}

::deep .message-item:hover {
    background: #222529;
}

::deep .message-meta {
    display: flex;
    align-items: baseline;
    gap: 8px;
    margin-bottom: 2px;
}

::deep .author {
    font-weight: 700;
    color: #fff;
    font-size: 0.95rem;
}

::deep .timestamp {
    font-size: 0.75rem;
    color: #717274;
}

::deep .message-content {
    font-size: 0.95rem;
    line-height: 1.46;
    word-break: break-word;
}

/* Reactions */

::deep .reactions {
    display: flex;
    gap: 4px;
    margin-top: 4px;
    flex-wrap: wrap;
}

::deep .reaction-badge {
    display: inline-flex;
    align-items: center;
    gap: 4px;
    background: #2c2d30;
    border: 1px solid #3c3f44;
    border-radius: 12px;
    padding: 2px 8px;
    font-size: 0.8rem;
    cursor: pointer;
    transition: background 0.15s;
}

::deep .reaction-badge:hover {
    background: #3c3f44;
}

/* Thread link */

::deep .thread-link {
    background: none;
    border: none;
    color: #1d9bd1;
    font-size: 0.8rem;
    font-weight: 600;
    cursor: pointer;
    padding: 4px 0;
    margin-top: 2px;
}

::deep .thread-link:hover {
    text-decoration: underline;
}

/* Hover actions */

::deep .message-actions {
    position: absolute;
    top: -8px;
    right: 12px;
    display: flex;
    gap: 2px;
    background: #1a1d21;
    border: 1px solid #3c3f44;
    border-radius: 6px;
    padding: 2px;
    box-shadow: 0 2px 8px rgba(0,0,0,0.3);
    z-index: 10;
}

::deep .action-btn {
    background: none;
    border: none;
    color: #d1d2d3;
    padding: 4px 8px;
    border-radius: 4px;
    cursor: pointer;
    font-size: 0.8rem;
    white-space: nowrap;
}

::deep .action-btn:hover {
    background: #2c2d30;
}

/* Emoji picker */

::deep .emoji-picker {
    position: absolute;
    right: 12px;
    top: 28px;
